CLASS LearningAgent
 FUNCTION init(performanceElement, critic, learningElement, problemGenerator):
 this.performanceElement = performanceElement // The agent that acts
 this.critic = critic // Evaluates performance
 this.learningElement = learningElement // Updates knowledge
 this.problemGenerator = problemGenerator // Generates experiences
 this.knowledge = {}

 FUNCTION run(environment, iterations):
 FOR i = 1 TO iterations:
 // Generate problem
 problem = this.problemGenerator.generate()

 // Act using performance element
 percept = environment.getPercept()
 action = this.performanceElement.decide(percept, this.knowledge)
 environment.execute(action)

 // Critic evaluates
 performance = this.critic.evaluate(action, percept)

 // Learning element updates knowledge
 this.knowledge = this.learningElement.update(
 this.knowledge, action, percept, performance
 )

 // After learning: performance element uses improved knowledge
 FUNCTION improve(action, result, reward):
 // Adjust action selection based on reward
 // Common algorithms: Q-learning, decision tree learning, etc.
 this.knowledge = this.learningElement.improve(
 this.knowledge, action, result, reward
 )

FUNCTION rationalAction(percept, knowledge, performanceMeasure):
 // 1. Update knowledge with new percept
 knowledge.add(percept)

 // 2. Determine possible actions
 possibleActions = getActions(percept)

 // 3. For each action, evaluate expected performance
 bestAction = null
 bestExpectedPerformance = -infinity

 FOR each action IN possibleActions:
 // Get predicted outcomes for this action
 outcomes = predictOutcomes(action, knowledge)

 // Calculate expected performance
 expectedPerformance = 0
 FOR each outcome IN outcomes:
 probability = outcome.probability
 performance = performanceMeasure(outcome.state)
 expectedPerformance = expectedPerformance + (probability * performance)

 // Track best action
 IF expectedPerformance > bestExpectedPerformance THEN:
 bestExpectedPerformance = expectedPerformance
 bestAction = action

 RETURN bestAction

// Key insight: Rationality depends on:
// - Current percept (what agent perceives NOW)
// - Knowledge accumulated (past percepts)
// - Performance measure (what defines success)
// NOT on outcomes that were unpredictable at decision time
